/* 토론 리스트 조회 ForumDAO.list */
SELECT ROW_NUMBER() OVER(ORDER BY forumStartDttm, regDttm) AS LINE_NO , totalCnt , forumCd , crsCreCd , forumCtgrCd , forumTitle , forumArtl , forumStartDttm , forumEndDttm , scoreAplyYn , scoreOpenYn , periodAfterWriteYn , forumOpenYn , teamForumCfgYn , teamCtgrCd , teamAtclOpenYn , prosConsForumCfg , prosConsRateOpenYn , prosConsModYn , regOpenYn , multiAtclYn , evalRsltOpenYn , evalCritUseYn , mutEvalYn , scoreOpenDttm , scoreRatio , stareType , avgScoreOpenYn , declsRegYn , pushNoticeYn , otherTeamViewYn , otherTeamAplyYn , delYn , forumAtclCnt , forumCmntCnt , forumUserTotalCnt , forumMyAtclCnt , forumMyCmntCnt , forumJoinUserCnt , forumMyScore -- , forumEvalCnt -- , forumStatus , forumMyFdbk FROM (
) TT WHERE TT.absent = 'Y' ORDER BY forumStartDttm DESC, regDttm DESC

mapper.update:
/*
	토론 정보 수정
	ForumDAO.updateForum
*/
UPDATE TB_LMS_DSCS
SET MOD_DTTM				= FN_DTTM()

, SBJCT_ID				= #{crsCreCd}


, DSCS_SDTTM			= #{forumStartDttm}


, DSCS_EDTTM			= #{forumEndDttm}


, MRK_RFLTYN				= #{scoreAplyYn}


, MRK_OYN				= #{scoreOpenYn}


, EVL_CTGRCD					= #{evalCtgr}


, PRD_AFTR_WRTYN		= #{periodAfterWriteYn}


, EXTD_EDTTM				= CASE WHEN #{extEndDttm} = '' THEN NULL ELSE #{extEndDttm} END


, DSCS_TYCD				= #{forumCtgrCd}


, DSCS_TTL				= #{forumTitle}


, DSCS_CTS				= #{forumArtl}


, DSCS_OYN				= #{forumOpenYn}


, MRK_OPEN_SDTTM			= #{scoreOpenDttm}


, TEAM_DSCS_ATCL_OYN			= #{teamAtclOpenYn}


, PROS_CONS_FORUM_CFG		= #{prosConsForumCfg}


, OKNOKRT_OYN	= #{prosConsRateOpenYn}


, REG_OPEN_YN				= #{regOpenYn}


, MLT_OPNN_REGYN				= #{multiAtclYn}


, OKNOK_MODYN			= #{prosConsModYn}


, TEAM_TYCD				= #{teamCtgrCd}


, EVL_RSLT_OYN			= #{evalRsltOpenYn}


, EVL_CRTR_USEYN			= #{evalCritUseYn}


, EVL_SDTTM			= CASE WHEN #{evalStartDttm} = '' THEN NULL ELSE #{evalStartDttm} END


, EVL_EDTTM				= CASE WHEN #{evalEndDttm} = '' THEN NULL ELSE #{evalEndDttm} END


, MRK_RFLTRT				= #{scoreRatio}


, AVG_MRK_OYN			= #{avgScoreOpenYn}


, DVCLAS_REGYN				= #{declsRegYn}


, MTL_EVLYN				= #{mutEvalYn}


, OTHER_VIEW_YN				= #{otherViewYn}


, APLY_CMNT_RSPNSYN				= #{aplyAsnYn}


, OTEAM_DSCS_INQYN 		= #{otherTeamViewYn}


, OTEAM_CMNT_WRT_PSBLYN		= #{otherTeamAplyYn}




		, LCTR_SCHDL_ID = NULL


		, LCTR_SCHDL_ID = #{lessonScheduleId}



WHERE DSCS_ID= #{forumCd}

mapper.insert:
/* 토론정보 등록 ForumDAO.insertForum */ INSERT INTO TB_LMS_DSCS ( DSCS_ID , SBJCT_ID , DSCS_SDTTM , DSCS_EDTTM , EXTD_EDTTM , MRK_RFLTYN , MRK_OYN , PRD_AFTR_WRTYN , DSCS_TYCD , DSCS_TTL , DSCS_CTS , DSCS_OYN , TEAM_DSCS_STNGYN , TEAM_TYCD , MRK_OPEN_SDTTM , TEAM_DSCS_ATCL_OYN , PROS_CONS_FORUM_CFG , OKNOKRT_OYN , REG_OPEN_YN , MLT_OPNN_REGYN , OKNOK_MODYN , EVL_RSLT_OYN , EVL_CRTR_USEYN , EVL_CTGRCD , EVL_SDTTM , EVL_EDTTM , MTL_EVLYN , MRK_RFLTRT , AVG_MRK_OYN , DVCLAS_REGYN , PUSH_NOTIYN , APLY_CMNT_RSPNSYN , OTEAM_DSCS_INQYN , OTEAM_CMNT_WRT_PSBLYN , LCTR_SCHDL_ID , RGTR_ID , FRST_INQ_DTTM , DELYN ) VALUES( #{forumCd} , #{crsCreCd} , #{forumStartDttm} , #{forumEndDttm} , #{extEndDttm} , NVL(#{scoreAplyYn},'N') , NVL(#{scoreOpenYn},'N') , NVL(#{periodAfterWriteYn},'N') , #{forumCtgrCd} , #{forumTitle} , #{forumArtl} , NVL(#{forumOpenYn},'Y') , NVL(#{teamForumCfgYn}, 'Y') , #{teamCtgrCd} , #{scoreOpenDttm} , NVL(#{teamAtclOpenYn},'N') , NVL(#{prosConsForumCfg},'N') , NVL(#{prosConsRateOpenYn},'N') , NVL(#{regOpenYn},'N') , NVL(#{multiAtclYn},'N') , NVL(#{prosConsModYn},'N') , NVL(#{evalRsltOpenYn},'N') , NVL(#{evalCritUseYn},'N') , NVL(#{evalCtgr},'1') , #{evalStartDttm} , #{evalEndDttm} , NVL(#{mutEvalYn},'N') , #{scoreRatio} , NVL(#{avgScoreOpenYn},'N') , NVL(#{declsRegYn},'N') , NVL(#{pushNoticeYn},'N') , NVL(#{aplyAsnYn},'N') , NVL(#{otherTeamViewYn}, 'N') , NVL(#{otherTeamAplyYn}, 'N')
, NULL
, #{lessonScheduleId}
, #{rgtrId} , FN_DTTM() , 'N' )

/* 토론정보 복사 ForumDAO.copyForum */ INSERT INTO TB_LMS_DSCS ( DSCS_ID , SBJCT_ID , DSCS_SDTTM , DSCS_EDTTM , MRK_RFLTYN , MRK_OYN , PRD_AFTR_WRTYN , DSCS_TYCD , DSCS_TTL , DSCS_CTS , DSCS_OYN , TEAM_DSCS_STNGYN
, MRK_OPEN_SDTTM , TEAM_DSCS_ATCL_OYN , PROS_CONS_FORUM_CFG , OKNOKRT_OYN , REG_OPEN_YN , MLT_OPNN_REGYN , OKNOK_MODYN , EVL_RSLT_OYN , EVL_CRTR_USEYN , EVL_CTGRCD , MTL_EVLYN , MRK_RFLTRT , AVG_MRK_OYN , DVCLAS_REGYN , PUSH_NOTIYN , APLY_CMNT_RSPNSYN , OTEAM_DSCS_INQYN , OTEAM_CMNT_WRT_PSBLYN , RGTR_ID , FRST_INQ_DTTM , DELYN ) SELECT #{forumCd} , #{crsCreCd} , DSCS_SDTTM , DSCS_EDTTM , MRK_RFLTYN , MRK_OYN , PRD_AFTR_WRTYN , DSCS_TYCD , DSCS_TTL , DSCS_CTS , DSCS_OYN , TEAM_DSCS_STNGYN
, MRK_OPEN_SDTTM , TEAM_DSCS_ATCL_OYN , PROS_CONS_FORUM_CFG , OKNOKRT_OYN , REG_OPEN_YN , MLT_OPNN_REGYN , OKNOK_MODYN , EVL_RSLT_OYN , EVL_CRTR_USEYN , EVL_CTGRCD , MTL_EVLYN , MRK_RFLTRT , AVG_MRK_OYN , DVCLAS_REGYN , PUSH_NOTIYN , APLY_CMNT_RSPNSYN , OTEAM_DSCS_INQYN , OTEAM_CMNT_WRT_PSBLYN , #{rgtrId}
, FN_DTTM_ADD_SEC(#{lineNo})
, FN_DTTM()
, DELYN FROM TB_LMS_DSCS WHERE DSCS_ID = #{copyForumCd}

mapper.select:
/* 내 강의에 등록된 토론 리스트 ForumDAO.listMyCreCrsForum */ SELECT ROW_NUMBER() OVER(ORDER BY A.SBJCTNM, B.FRST_INQ_DTTM DESC) AS lineNo , B.DSCS_ID , B.DSCS_TTL , B.DSCS_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'DSCS_TYCD' AND CD = B.DSCS_TYCD LIMIT 1) AS FORUM_CTGR_NM , A.SBJCT_ID , A.CRS_ID , A.SBJCTNM , A.DVCLAS_NO , COUNT(1) OVER() AS totalCnt FROM ( SELECT A.SBJCT_ID , A.SBJCT_ID , A.CRS_ID , A.SBJCTNM , A.DVCLAS_NO FROM TB_LMS_SBJCT A JOIN SBJCT_PROF B ON A.SBJCT_ID = B.SBJCT_ID AND B.PROF_TYCD = 'PROFESSOR' AND B.RPRSYN = 'Y' AND B.USER_ID = #{rgtrId} JOIN TB_LMS_TERM_CRE_CRS_RLTN C ON A.SBJCT_ID = C.SBJCT_ID AND C.CRS_SMSTR_ID = #{termCd} WHERE A.DELYN = 'N' AND A.SBJCT_TYCD = 'UNI'
AND A.SBJCT_ID = #{creYear}
AND A.CRS_ID = #{creTerm}
AND A.SBJCT_ID = #{crsCreCd}
) A JOIN TB_LMS_DSCS B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' WHERE 1 = 1
AND LOWER(B.DSCS_TTL) LIKE CONCAT('%', LOWER(#{searchValue}), '%')
LIMIT #{firstIndex}, #{listScale}

mapper.update:
/*
	성적반영비율 초기화
	ForumDAO.setScoreRatio
*/
UPDATE TB_LMS_DSCS
	SET MRK_RFLTRT = #{scoreRatio}
WHERE DSCS_ID = #{forumCd}

mapper.select:
/*
	stdNo 조회
	ForumDAO.getStdNo
*/
SELECT
	STD_ID
FROM TB_LMS_ATNDLC_SBJCT
WHERE USER_ID = #{userId}
	AND ATNDLC_STSCD = 'S'
	AND SBJCT_ID = #{crsCreCd}
